// // This module calculates the 8-bit checksum by performing a bitwise AND operation on all input bits.
module checksum_calculator(
    input [7:0] data,
    output reg [7:0] checksum
);

always @* begin
    checksum = data[0] ^ data[1] ^ data[2] ^ data[3] ^ data[4] ^ data[5] ^ data[6] ^ data[7];
end

endmodule
